// SVG icon component type
type SVGIcon = () => React.ReactElement;

export const iconRegistry: Record<string, LucideIcon | SVGIcon> = {
  // Navigation & UI
  layout: Layout,
  server: Server,
  database: Database,
  brain: Brain,
  cloud: Cloud,
  calendar: Calendar,
  briefcase: Briefcase,
  mapPin: MapPin,
  user: User,
  badge: BadgeCheck,
  mail: Mail,
  phone: Phone,
  languages: Languages,
  clock: Clock,
  monitor: Monitor,
  externalLink: ExternalLink,
  github: Github,
  linkedin: Linkedin,
  twitter: Twitter,
  chevronDown: ChevronDown,
  menu: Menu,
  close: X,
  send: Send,
  checkCircle: CheckCircle,
  alertCircle: AlertCircle,
  loader: Loader2,
  arrowUp: ArrowUp,
  download: Download,
  eye: Eye,
  code: Code2,
  cpu: Cpu,
  globe: Globe,
  zap: Zap,
  shield: Shield,
  copy: Copy,
  check: Check,
  link: Link,

  // Technology icons
  react: ReactIcon,
  nextdotjs: NextJsIcon,
  typescript: TypeScriptIcon,
  javascript: JavaScriptIcon,
  tailwindcss: TailwindIcon,
  redux: Code2,
  framer: Zap,
  shadcnui: Layout,
  nodedotjs: NodeJsIcon,
  express: Server,
  nestjs: Cpu,
  fastapi: Zap,
  python: PythonIcon,
  graphql: Globe,
  trpc: Code2,
  socketdotio: Zap,
  postgresql: Database,
  mongodb: Database,
  prisma: Database,
  sqlalchemy: Database,
  redis: Zap,
  pinecone: Database,
  openai: Brain,
  googlegemini: Brain,
  langchain: Link,
  promptengineering: Brain,
  llm: Brain,
  vectorsearch: Database,
  docker: DockerIcon,
  githubactions: GitFork,
  railway: Globe,
  amazonwebservices: AwsIcon,
  nginx: Globe,
  git: GitFork,
  linux: Globe,
  terraform: Globe,
  kubernetes: Cloud,
};

// Helper function to get an icon by name
export const getIcon = (name: string): LucideIcon | SVGIcon => {
  return iconRegistry[name] || Code2;
};

// Helper to check if icon exists
export const hasIcon = (name: string): boolean => {
  return name in iconRegistry;
};
